public class Student {
    String name;
    int age;

    // Default constructor: sets name to "Unknown" and age to 0

    // Parameterized constructor: accepts name and age

    public void display() {
        System.out.println("Name: " + name + ", Age: " + age);
    }

    public static void main(String[] args) {
        Student s1 = new Student();           // uses default constructor
        Student s2 = new Student("Alice", 20); // uses parameterized constructor
        s1.display();
        s2.display();
    }
}

public class Counter {
    int count;

    // Constructor: initialise count to 0

    // increment(): adds 1 to count

    // display(): prints "Counter: <count>"

    public static void main(String[] args) {
        Counter c1 = new Counter();
        Counter c2 = new Counter();

        c1.increment();
        c1.increment();
        c1.increment();

        c2.increment();

        c1.display(); // Expected: Counter: 3
        c2.display(); // Expected: Counter: 1
    }
}
